// Necessary casts for type conversion
void necessary_cast_examples() {
    int i = 10;
    float f = (float) i;       // Compliant: int to float conversion

    double d = 3.14159;
    int truncated = (int) d;   // Compliant: double to int conversion

    void* generic_ptr = malloc(sizeof(int));
    int* int_ptr = (int*) generic_ptr;  // Compliant: void* to specific type
}

// Necessary casts for arithmetic
void arithmetic_cast_examples() {
    int a = 5, b = 2;
    double result = (double) a / b;  // Compliant: prevents integer division

    unsigned int ui = 100;
    int si = (int) ui;          // Compliant: unsigned to signed

    char c = 'A';
    int ascii = (int) c;        // Compliant: char to int for ASCII value
}

// Necessary casts for function pointers and const
void necessary_advanced_casts() {
    const char* const_str = "hello";
    char* mutable_str = (char*) const_str;  // Compliant: removing const

    // Function pointer with different but compatible signature
    void (*generic_func)(void) = (void(*)(void)) my_function;  // Compliant

    // Pointer arithmetic requiring casts
    char* buffer = malloc(100);
    int* int_buffer = (int*) buffer;  // Compliant: alignment consideration
}
